toolArgs.new_str:
using sv_ec98094e181c4d91830213e7856fc087.Components;
using sv_ec98094e181c4d91830213e7856fc087.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

builder.Services.AddScoped<ReviewService>();

// Increase SignalR max message size to support 5 MB file uploads.
builder.Services.AddSignalR(options =>
{
    options.MaximumReceiveMessageSize = 6 * 1024 * 1024; // 6 MB to allow overhead
});

